# Based on the typical contract for this project, implement a standalone HTML file
# for a boids simulation that:
# - creates a full-page canvas
# - implements basic boids rules: alignment, cohesion, separation
# - provides simple controls (play/pause, slider for speed or count)
# - includes compact, well-structured JS and CSS embedded in the HTML
# - no external dependencies
# We'll write the file to output/boids-simulation/index.html

html = """<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
