<script>
(function(){
  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d', { alpha: true });
  let W = canvas.width = innerWidth;
  let H = canvas.height = innerHeight;
  const DPR = Math.max(1, window.devicePixelRatio || 1);
  canvas.width = Math.floor(W * DPR);
  canvas.height = Math.floor(H * DPR);
  canvas.style.width = W + 'px';
  canvas.style.height = H + 'px';
  ctx.scale(DPR, DPR);

  // UI
  const toggleBtn = document.getElementById('toggle');
  const countInput = document.getElementById('count');
  const countLabel = document.getElementById('countLabel');
  const speedInput = document.getElementById('speed');
  const speedLabel = document.getElementById('speedLabel');
  const resetBtn = document.getElementById('reset');
  const fpsEl = document.getElementById('fps');
  const statsCount = document.getElementById('statsCount');

  // Simulation parameters (tunables)
  let params = {
    boidCount: Number(countInput.value),
    maxSpeed: 2.0,
    maxForce: 0.05,
    perception: 50,
    alignWeight: 1.0,
    cohesionWeight: 0.8,
    separationWeight: 1.4,
    separationDistance: 24,
    wrap: true,
    paused: false,
    timeScale: Number(speedInput.value)
  };

  countLabel.textContent = params.boidCount;
  speedLabel.textContent = params.timeScale.toFixed(1);

  // Utility vector helpers (lightweight)
  function v(x=0,y=0){ return {x:x,y:y}; }
  function vAdd(a,b){ a.x+=b.x; a.y+=b.y; return a; }
  function vSub(a,b){ return {x:a.x-b.x, y:a.y-b.y}; }
  function vMul(a,s){ a.x*=s; a.y*=s; return a; }
  function vDiv(a,s){ if(s!==0){ a.x/=s; a.y/=s; } return a; }
  function vLen(a){ return Math.hypot(a.x,a.y); }
  function vSetMag(a,m){ const L=vLen(a)||1; a.x = (a.x/L)*m; a.y = (a.y/L)*m; return a; }
  function vLimit(a, max){ const L = vLen(a); if(L>max){ vSetMag(a, max); } return a; }

  // Boid class
  class Boid {
    constructor(x,y){
      this.pos = v(x,y);
      const angle = Math.random()*Math.PI*2;
      this.vel = v(Math.cos(angle), Math.sin(angle));
      vMul(this.vel, params.maxSpeed * (0.5 + Math.random()*0.8));
      this.acc = v(0,0);
      this.size = 6 + Math.random()*4;
      this.hue = 180 + Math.random()*80; // bluish
    }
    edges(){
      if(params.wrap){
        if(this.pos.x > W) this.pos.x = 0;
        if(this.pos.x < 0) this.pos.x = W;
        if(this.pos.y > H) this.pos.y = 0;
        if(this.pos.y < 0) this.pos.y = H;
      } else {
        if(this.pos.x > W || this.pos.x < 0) this.vel.x *= -1;
        if(this.pos.y > H || this.pos.y < 0) this.vel.y *= -1;
      }
    }
    applyForce(f){ vAdd(this.acc, f); }
    flock(boids){
      const perception = params.perception;
      let total = 0;
      let steerAlign = v(0,0);
      let steerCohesion = v(0,0);
      let steerSeparation = v(0,0);
      for(let other of boids){
        if(other===this) continue;
        const d = Math.hypot(this.pos.x - other.pos.x, this.pos.y - other.pos.y);
        if(d < perception){
          // alignment
          vAdd(steerAlign, other.vel);
          // cohesion
          vAdd(steerCohesion, other.pos);
          // separation
          let diff = vSub(this.pos, other.pos);
          if(d > 0) vDiv(diff, d); // weight by distance
          vAdd(steerSeparation, diff);
          total++;
        }
      }
      if(total > 0){
        // Alignment
        vDiv(steerAlign, total);
        vSetMag(steerAlign, params.maxSpeed);
        vSub(steerAlign, this.vel);
        vLimit(steerAlign, params.maxForce);
        vMul(steerAlign, params.alignWeight);

        // Cohesion
        vDiv(steerCohesion, total);
        steerCohesion = vSub(steerCohesion, this.pos);
        vSetMag(steerCohesion, params.maxSpeed);
        vSub(steerCohesion, this.vel);
        vLimit(steerCohesion, params.maxForce);
        vMul(steerCohesion, params.cohesionWeight);

        // Separation
        vDiv(steerSeparation, total);
        vSetMag(steerSeparation, params.maxSpeed);
        vSub(steerSeparation, this.vel);
        vLimit(steerSeparation, params.maxForce * 1.5);
        vMul(steerSeparation, params.separationWeight);

        vAdd(this.acc, steerAlign);
        vAdd(this.acc, steerCohesion);
        vAdd(this.acc, steerSeparation);
      }
    }
    update(dt){
      // dt is scaled by params.timeScale
      vAdd(this.vel, vMul(v(this.acc.x,this.acc.y), dt));
      vLimit(this.vel, params.maxSpeed * Math.max(0.2, params.timeScale));
      vAdd(this.pos, vMul(v(this.vel.x,this.vel.y), dt));
      this.acc.x = 0; this.acc.y = 0;
    }
    draw(ctx){
      const angle = Math.atan2(this.vel.y, this.vel.x);
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(angle);
      // draw triangle
      ctx.beginPath();
      ctx.moveTo(this.size, 0);
      ctx.lineTo(-this.size*0.6, this.size*0.5);
      ctx.lineTo(-this.size*0.6, -this.size*0.5);
      ctx.closePath();
      ctx.fillStyle = `hsla(${this.hue}, 90%, 60%, 0.95)`;
      ctx.fill();
      ctx.restore();
    }
  }

  // Create boids
  let boids = [];
  function populate(n){
    boids = [];
    for(let i=0;i<n;i++){
      const x = Math.random()*W;
      const y = Math.random()*H;
      boids.push(new Boid(x,y));
    }
  }
  populate(params.boidCount);
  statsCount.textContent = boids.length;

  // Animation loop
  let last = performance.now();
  let frames = 0;
  let fpsTimer = performance.now();
  function frame(now){
    const rawDt = (now - last)/16.6667; // relative to 60fps frame
    last = now;
    if(!params.paused){
      const dt = rawDt * params.timeScale;
      // Update boids
      for(let b of boids){
        b.flock(boids);
      }
      for(let b of boids){
        b.update(dt);
        b.edges();
      }
    }
    // draw
    ctx.clearRect(0,0,W,H);
    // subtle background vignette
    const g = ctx.createLinearGradient(0,0,0,H);
    g.addColorStop(0, 'rgba(255,255,255,0.01)');
    g.addColorStop(1, 'rgba(0,0,0,0.05)');
    ctx.fillStyle = g;
    ctx.fillRect(0,0,W,H);

    // draw boids
    for(let b of boids){
      b.draw(ctx);
    }

    // HUD overlay is done by HTML elements; update FPS
    frames++;
    if(now - fpsTimer > 500){
      const fps = Math.round((frames*1000)/(now - fpsTimer));
      fpsEl.textContent = fps;
      frames = 0;
      fpsTimer = now;
    }

    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

  // Responsiveness
  window.addEventListener('resize', ()=> {
    W = canvas.width = innerWidth;
    H = canvas.height = innerHeight;
    canvas.width = Math.floor(W * DPR);
    canvas.height = Math.floor(H * DPR);
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    ctx.setTransform(1,0,0,1,0,0);
    ctx.scale(DPR, DPR);
  });

  // UI interactions
  toggleBtn.addEventListener('click', ()=>{
    params.paused = !params.paused;
    toggleBtn.textContent = params.paused ? 'Play' : 'Pause';
  });
  countInput.addEventListener('input', (e)=>{
    const n = Number(e.target.value);
    countLabel.textContent = n;
    // Adjust population smoothly
    const diff = n - boids.length;
    if(diff > 0){
      for(let i=0;i<diff;i++){
        boids.push(new Boid(Math.random()*W, Math.random()*H));
      }
    } else if(diff < 0){
      boids.splice(diff); // removes from end
    }
    params.boidCount = n;
    statsCount.textContent = boids.length;
  });
  speedInput.addEventListener('input', (e)=>{
    const v = Number(e.target.value);
    params.timeScale = v;
    speedLabel.textContent = v.toFixed(1);
  });
  resetBtn.addEventListener('click', ()=>{
    populate(params.boidCount);
    statsCount.textContent = boids.length;
  });

  // Add boids on click
  canvas.addEventListener('click', (e)=>{
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    // add a few boids near click
    for(let i=0;i<6;i++){
      const b = new Boid(x + (Math.random()-0.5)*40, y + (Math.random()-0.5)*40);
      boids.push(b);
    }
    params.boidCount = boids.length;
    countInput.value = boids.length;
    countLabel.textContent = boids.length;
    statsCount.textContent = boids.length;
  });

  // Touch: add on tap
  canvas.addEventListener('touchstart', (e)=>{
    const t = e.touches[0];
    if(!t) return;
    const rect = canvas.getBoundingClientRect();
    const x = t.clientX - rect.left;
    const y = t.clientY - rect.top;
    for(let i=0;i<4;i++){
      boids.push(new Boid(x + (Math.random()-0.5)*40, y + (Math.random()-0.5)*40));
    }
    params.boidCount = boids.length;
    countInput.value = boids.length;
    countLabel.textContent = boids.length;
    statsCount.textContent = boids.length;
  });

  // Keyboard shortcuts
  window.addEventListener('keydown', (e)=>{
    if(e.key === ' ') { e.preventDefault(); toggleBtn.click(); }
    if(e.key === 'r' || e.key === 'R') resetBtn.click();
  });

  // Expose for debug in console
  window._boids = { boids, params, populate };

})();
</script>
</body>
</html>
